export function PatientRegisterPage() {
  const [form, setForm] = useState({ firstName:'', lastName:'', email:'', password:'', phone:'', dateOfBirth:'', gender:'', bloodGroup:'', address:'' });
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
